import os
import uuid
import json
import hashlib
from pathlib import Path
from datetime import datetime
from functools import wraps

from flask import Flask, request, jsonify, send_file, abort

app = Flask(__name__)

# Configuration
BASE_UPLOAD_DIR = os.environ.get("UPLOAD_DIR", "/tmp/file_explorer_uploads")
USER_DB_FILE = os.environ.get("USER_DB", "/tmp/file_explorer_users.json")

# Ensure base upload directory exists
os.makedirs(BASE_UPLOAD_DIR, exist_ok=True)

# In-memory file ID mapping: file_id -> {"user": user_id, "relative_path": relative_path}
# In production, this would be a database
file_id_mapping = {}


def _load_or_init_user_db():
    """Load or initialize the user database."""
    if os.path.exists(USER_DB_FILE):
        with open(USER_DB_FILE, "r") as f:
            return json.load(f)
    return {}


def _save_user_db(db):
    """Save the user database."""
    with open(USER_DB_FILE, "w") as f:
        json.dump(db, f)


def _get_user_root(user_id: str) -> Path:
    """Get the root directory for a given user, creating it if necessary."""
    # Sanitize user_id to prevent any path issues
    safe_user_id = hashlib.sha256(user_id.encode()).hexdigest()[:32]
    user_root = Path(BASE_UPLOAD_DIR) / safe_user_id
    user_root.mkdir(parents=True, exist_ok=True)
    return user_root.resolve()


def _validate_and_resolve_path(user_root: Path, user_path: str) -> Path:
    """
    Securely resolve a user-provided path against the user's root directory.
    
    This function:
    1. Rejects absolute paths
    2. Resolves the full canonical path using Path.resolve()
    3. Verifies the resolved path is within the user's root directory
    4. Prevents path traversal attacks
    
    Returns the resolved Path object.
    Raises ValueError if the path is invalid or attempts traversal.
    """
    if not user_path:
        return user_root

    # Reject absolute paths immediately
    if os.path.isabs(user_path):
        raise ValueError("Absolute paths are not allowed")

    # Reject null bytes
    if "\x00" in user_path:
        raise ValueError("Null bytes are not allowed in paths")

    # Construct and resolve the full path canonically
    # Path.resolve() follows symlinks and produces an absolute canonical path
    user_root_resolved = user_root.resolve()
    full_path = (user_root_resolved / user_path).resolve()

    # Critical security check: ensure the resolved path is under the user's root
    # We use os.path.commonpath or check that the resolved path starts with the root
    try:
        full_path.relative_to(user_root_resolved)
    except ValueError:
        raise ValueError(
            f"Path traversal detected: resolved path is outside the allowed directory"
        )

    return full_path


def _generate_file_id(user_id: str, relative_path: str) -> str:
    """Generate a unique file ID for server-side mapping."""
    # Check if we already have an ID for this user+path combination
    for fid, info in file_id_mapping.items():
        if info["user"] == user_id and info["relative_path"] == relative_path:
            return fid

    file_id = str(uuid.uuid4())
    file_id_mapping[file_id] = {
        "user": user_id,
        "relative_path": relative_path,
    }
    return file_id


def _resolve_file_id(file_id: str, user_id: str) -> Path:
    """
    Resolve a file ID to a validated path using server-side mapping.
    This is the preferred approach - using allowlisted file identifiers
    instead of raw user-supplied paths.
    """
    if file_id not in file_id_mapping:
        raise ValueError(f"Unknown file ID: {file_id}")

    mapping = file_id_mapping[file_id]
    if mapping["user"] != user_id:
        raise ValueError("Access denied: file belongs to another user")

    user_root = _get_user_root(user_id)
    # Still validate even though we control the mapping, defense in depth
    return _validate_and_resolve_path(user_root, mapping["relative_path"])


def _get_file_info(file_path: Path, user_root: Path, user_id: str) -> dict:
    """Get metadata about a file or directory."""
    stat = file_path.stat()
    relative_path = str(file_path.relative_to(user_root))
    if relative_path == ".":
        relative_path = ""

    file_id = _generate_file_id(user_id, relative_path)

    info = {
        "file_id": file_id,
        "name": file_path.name or "/",
        "relative_path": relative_path,
        "is_directory": file_path.is_dir(),
        "is_file": file_path.is_file(),
        "size_bytes": stat.st_size if file_path.is_file() else None,
        "created": datetime.fromtimestamp(stat.st_ctime).isoformat(),
        "modified": datetime.fromtimestamp(stat.st_mtime).isoformat(),
        "permissions": oct(stat.st_mode)[-3:],
    }

    if file_path.is_file():
        info["extension"] = file_path.suffix.lower() if file_path.suffix else None
        info["mime_type"] = _guess_mime_type(file_path)

    return info


def _guess_mime_type(file_path: Path) -> str:
    """Guess MIME type based on file extension."""
    import mimetypes
    mime_type, _ = mimetypes.guess_type(str(file_path))
    return mime_type or "application/octet-stream"


def require_user(f):
    """Decorator to extract and validate user ID from request."""
    @wraps(f)
    def decorated(*args, **kwargs):
        # In production, this would come from authentication middleware
        user_id = request.headers.get("X-User-ID")
        if not user_id:
            return jsonify({"error": "Missing X-User-ID header"}), 401
        if not user_id.isalnum() or len(user_id) > 64:
            return jsonify({"error": "Invalid user ID format"}), 400
        kwargs["user_id"] = user_id
        return f(*args, **kwargs)
    return decorated


@app.route("/api/files/list", methods=["GET"])
@require_user
def list_directory(user_id):
    """
    List contents of a directory.
    
    Query params:
        path: relative path to directory (default: root)
        
    Returns list of file/directory info objects.
    """
    user_path = request.args.get("path", "")
    user_root = _get_user_root(user_id)

    try:
        resolved_path = _validate_and_resolve_path(user_root, user_path)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    if not resolved_path.exists():
        return jsonify({"error": "Path does not exist"}), 404

    if not resolved_path.is_dir():
        return jsonify({"error": "Path is not a directory"}), 400

    entries = []
    try:
        for entry in sorted(resolved_path.iterdir()):
            # Skip hidden files/directories starting with .
            if entry.name.startswith("."):
                continue
            try:
                entry_info = _get_file_info(entry, user_root, user_id)
                entries.append(entry_info)
            except (PermissionError, OSError):
                # Skip entries we can't access
                continue
    except PermissionError:
        return jsonify({"error": "Permission denied"}), 403

    current_relative = str(resolved_path.relative_to(user_root))
    if current_relative == ".":
        current_relative = ""

    return jsonify({
        "current_directory": current_relative,
        "parent_directory": str(Path(current_relative).parent) if current_relative else None,
        "total_entries": len(entries),
        "entries": entries,
    })


