@app.route("/api/files/upload", methods=["POST"])
@require_user
def upload_file(user_id):
    """
    Upload a file to the user's directory.
    
    Form data:
        file: the file to upload
        path: (optional) relative directory path to upload into
    """
    if "file" not in request.files:
        return jsonify({"error": "No file provided"}), 400

    uploaded_file = request.files["file"]
    if not uploaded_file.filename:
        return jsonify({"error": "No filename provided"}), 400

    target_dir_path = request.form.get("path", "")
    user_root = _get_user_root(user_id)

    # Validate target directory
    try:
        resolved_dir = _validate_and_resolve_path(user_root, target_dir_path)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    if not resolved_dir.exists():
        return jsonify({"error": "Target directory does not exist"}), 404

    if not resolved_dir.is_dir():
        return jsonify({"error": "Target path is not a directory"}), 400

    # Sanitize the uploaded filename
    # Only take the basename to prevent directory traversal via filename
    original_filename = uploaded_file.filename
    safe_filename = Path(original_filename).name

    # Reject empty or dangerous filenames
    if not safe_filename or safe_filename.startswith(".") or safe_filename in (".", ".."):
        return jsonify({"error": "Invalid filename"}), 400

    # Remove any remaining problematic characters
    safe_filename = "".join(
        c for c in safe_filename
        if c.isalnum() or c in ".-_ "
    ).strip()

    if not safe_filename:
        return jsonify({"error": "Filename contains only invalid characters"}), 400

    # Construct final path and validate again
    final_path = (resolved_dir / safe_filename).resolve()
    try:
        final_path.relative_to(user_root.resolve())
    except ValueError:
        return jsonify({"error": "Invalid file path"}), 400

    # Handle filename conflicts
    if final_path.exists():
        stem = final_path.stem
        suffix = final_path.suffix
        counter = 1
        while final_path.exists():
            new_name = f"{stem}_{counter}{suffix}"
            final_path = (resolved_dir / new_name).resolve()
            try:
                final_path.relative_to(user_root.resolve())
            except ValueError:
                return jsonify({"error": "Invalid file path"}), 400
            counter += 1

    try:
        uploaded_file.save(str(final_path))
    except (PermissionError, OSError) as e:
        return jsonify({"error": f"Failed to save file: {str(e)}"}), 500

    info = _get_file_info(final_path, user_root, user_id)
    return jsonify({
        "message": "File uploaded successfully",
        "file": info,
    }), 201


@app.route("/api/files/mkdir", methods=["POST"])
@require_user
def create_directory(user_id):
    """
    Create a new directory.
    
    JSON body:
        path: relative path for the new directory
    """
    data = request.get_json()
    if not data or "path" not in data:
        return jsonify({"error": "Missing path in request body"}), 400

    user_path = data["path"]
    if not user_path:
        return jsonify({"error": "Path cannot be empty"}), 400

    user_root = _get_user_root(user_id)

    try:
        resolved_path = _validate_and_resolve_path(user_root, user_path)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    if resolved_path.exists():
        return jsonify({"error": "Path already exists"}), 409

    # Ensure parent directory exists and is within user root
    parent = resolved_path.parent
    try:
        parent.relative_to(user_root.resolve())
    except ValueError:
        return jsonify({"error": "Invalid parent directory"}), 400

    if not parent.exists():
        return jsonify({"error": "Parent directory does not exist"}), 404

    try:
        resolved_path.mkdir(parents=False, exist_ok=False)
    except (PermissionError, OSError) as e:
        return jsonify({"error": f"Failed to create directory: {str(e)}"}), 500

    info = _get_file_info(resolved_path, user_root, user_id)
    return jsonify({
        "message": "Directory created successfully",
        "directory": info,
    }), 201


@app.route("/api/files/search", methods=["GET"])
@require_user
def search_files(user_id):
    """
    Search for files by name pattern.
    
    Query params:
        query: search string (matched against filenames)
        path: (optional) directory to search in
    """
    query = request.args.get("query", "").strip()
    if not query:
        return jsonify({"error": "Missing query parameter"}), 400

    search_path = request.args.get("path", "")
    user_root = _get_user_root(user_id)

    try:
        resolved_search_root = _validate_and_resolve_path(user_root, search_path)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    if not resolved_search_root.exists() or not resolved_search_root.is_dir():
        return jsonify({"error": "Search directory does not exist"}), 404

    results = []
    max_results = 100

    try:
        for item in resolved_search_root.rglob("*"):
            if len(results) >= max_results:
                break

            if item.name.startswith("."):
                continue

            # Verify each found path is still within user root (defense in depth against symlinks)
            try:
                item.resolve().relative_to(user_root.resolve())
            except ValueError:
                continue

            if query.lower() in item.name.lower():
                try:
                    info = _get_file_info(item, user_root, user_id)
                    results.append(info)
                except (PermissionError, OSError):
                    continue
    except PermissionError:
        return jsonify({"error": "Permission denied during search"}), 403

    return jsonify({
        "query": query,
        "total_results": len(results),
        "results": results,
    })


